import { Component, OnDestroy, OnInit } from '@angular/core';
import { interval, Subscription } from 'rxjs';
import { WeighingService, WeighingTransaction, WeightReading } from '../../services/weighing.service';

@Component({
  selector: 'app-weighing-form',
  templateUrl: './weighing-form.component.html',
  styleUrls: ['./weighing-form.component.css']
})
export class WeighingFormComponent implements OnInit, OnDestroy {

  productionOrderId = '';
  batchId = '';
  userId = '';

  currentWeight: WeightReading | null = null;
  capturedReadings: number[] = [];

  recentTransactions: WeighingTransaction[] = [];

  submitting = false;
  statusMessage = '';
  statusIsError = false;

  private pollSub?: Subscription;
  private listSub?: Subscription;

  constructor(private weighingService: WeighingService) {}

  ngOnInit(): void {
    // Poll the live scale reading every second
    this.pollSub = interval(1000).subscribe(() => {
      this.weighingService.getCurrentWeight().subscribe({
        next: (reading) => this.currentWeight = reading,
        error: () => { /* scale temporarily unreachable - keep last known reading on screen */ }
      });
    });

    this.refreshRecent();
    // Refresh the "pending sync" list periodically
    this.listSub = interval(15000).subscribe(() => this.refreshRecent());
  }

  ngOnDestroy(): void {
    this.pollSub?.unsubscribe();
    this.listSub?.unsubscribe();
  }

  captureReading(): void {
    if (this.currentWeight) {
      this.capturedReadings.push(this.currentWeight.weight);
    }
  }

  removeReading(index: number): void {
    this.capturedReadings.splice(index, 1);
  }

  get totalWeight(): number {
    return Math.round(this.capturedReadings.reduce((a, b) => a + b, 0) * 100) / 100;
  }

  get canSubmit(): boolean {
    return !!this.productionOrderId && !!this.batchId && !!this.userId
      && this.capturedReadings.length > 0 && !this.submitting;
  }

  submit(): void {
    if (!this.canSubmit) return;

    this.submitting = true;
    this.statusMessage = '';

    this.weighingService.submitTransaction({
      productionOrderId: this.productionOrderId,
      batchId: this.batchId,
      userId: this.userId,
      weightReadings: this.capturedReadings,
      unit: this.currentWeight?.unit || 'KG'
    }).subscribe({
      next: (tx) => {
        this.submitting = false;
        if (tx.status === 'SENT') {
          this.statusIsError = false;
          this.statusMessage = `Sent to SAP successfully (ref: ${tx.sapReference}).`;
        } else {
          this.statusIsError = true;
          this.statusMessage = `Saved locally, but SAP post failed — it will retry automatically. (${tx.lastError ?? ''})`;
        }
        this.resetForm();
        this.refreshRecent();
      },
      error: (err) => {
        this.submitting = false;
        this.statusIsError = true;
        this.statusMessage = 'Could not save the transaction: ' + (err?.error?.message || err.message);
      }
    });
  }

  private resetForm(): void {
    this.productionOrderId = '';
    this.batchId = '';
    this.userId = '';
    this.capturedReadings = [];
  }

  private refreshRecent(): void {
    this.weighingService.getRecentTransactions().subscribe({
      next: (list) => this.recentTransactions = list,
      error: () => { /* ignore, transient */ }
    });
  }

  get pendingCount(): number {
    return this.recentTransactions.filter(t => t.status !== 'SENT').length;
  }
}
<div class="station">

  <header>
    <h1>Weighing Station</h1>
    <span class="sync-badge" [class.warn]="pendingCount > 0">
      {{ pendingCount }} pending sync
    </span>
  </header>

  <section class="scale-panel">
    <div class="weight-display" [class.unstable]="currentWeight && !currentWeight.stable">
      <span class="value">{{ currentWeight?.weight ?? '---' }}</span>
      <span class="unit">{{ currentWeight?.unit ?? '' }}</span>
    </div>
    <div class="scale-status">
      {{ currentWeight?.stable ? 'Stable reading' : 'Settling…' }}
    </div>
    <button class="capture-btn" (click)="captureReading()" [disabled]="!currentWeight">
      Capture reading
    </button>
  </section>

  <section class="readings-panel" *ngIf="capturedReadings.length > 0">
    <h3>Captured weighments</h3>
    <ul>
      <li *ngFor="let r of capturedReadings; let i = index">
        {{ r }} {{ currentWeight?.unit }}
        <button class="remove-btn" (click)="removeReading(i)">✕</button>
      </li>
    </ul>
    <div class="total">Total: <strong>{{ totalWeight }} {{ currentWeight?.unit }}</strong></div>
  </section>

  <section class="entry-panel">
    <label>
      Production Order ID
      <input type="text" [(ngModel)]="productionOrderId" placeholder="Scan or enter" />
    </label>
    <label>
      Batch ID
      <input type="text" [(ngModel)]="batchId" placeholder="Scan or enter" />
    </label>
    <label>
      User ID
      <input type="text" [(ngModel)]="userId" placeholder="Operator ID" />
    </label>

    <button class="submit-btn" (click)="submit()" [disabled]="!canSubmit">
      {{ submitting ? 'Sending…' : 'Submit weighing' }}
    </button>

    <div class="status-message" *ngIf="statusMessage" [class.error]="statusIsError">
      {{ statusMessage }}
    </div>
  </section>

  <section class="recent-panel">
    <h3>Recent transactions</h3>
    <table>
      <thead>
        <tr><th>Order</th><th>Batch</th><th>Weight</th><th>Status</th></tr>
      </thead>
      <tbody>
        <tr *ngFor="let t of recentTransactions">
          <td>{{ t.productionOrderId }}</td>
          <td>{{ t.batchId }}</td>
          <td>{{ t.totalWeight }} {{ t.unit }}</td>
          <td [class]="'status-' + t.status.toLowerCase()">{{ t.status }}</td>
        </tr>
      </tbody>
    </table>
  </section>

</div>
